```javascript
// 方案逻辑：分析 base64 蒙版图，提取非透明区域的矩形坐标
async function getBBoxFromMask(maskDataUrl) {
    return new Promise((resolve) => {
        const img = new Image();
        img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            const ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0);
            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height).data;

            let minX = canvas.width, minY = canvas.height, maxX = 0, maxY = 0;
            let found = false;

            for (let y = 0; y < canvas.height; y++) {
                for (let x = 0; x < canvas.width; x++) {
                    const alpha = imageData[(y * canvas.width + x) * 4 + 3];
                    const red = imageData[(y * canvas.width + x) * 4]; // 假设蒙版是白色或红色
                    if (alpha > 10 || red > 10) { 
                        if (x < minX) minX = x; if (x > maxX) maxX = x;
                        if (y < minY) minY = y; if (y > maxY) maxY = y;
                        found = true;
                    }
                }
            }
            if (!found) return resolve(null);

            // 转换为百分比坐标，方便复用已有的裁剪逻辑 [ymin, xmin, ymax, xmax]
            resolve([
                (minY / canvas.height) * 100, (minX / canvas.width) * 100,
                (maxY / canvas.height) * 100, (maxX / canvas.width) * 100
            ]);
        };
        img.src = maskDataUrl;
    });
}
```

